package com.example.auth

import android.content.Context
import android.content.SharedPreferences

class AuthManager private constructor(
    private val prefs: SharedPreferences
) {

    data class AuthState(
        val isLoggedIn: Boolean,
        val userId: String?,
        val authToken: String?
    )

    fun isLoggedIn(): Boolean = prefs.getBoolean(KEY_LOGGED_IN, false)

    fun getUserId(): String? = prefs.getString(KEY_USER_ID, null)

    fun getAuthToken(): String? = prefs.getString(KEY_AUTH_TOKEN, null)

    fun getAuthState(): AuthState {
        val loggedIn = isLoggedIn()
        val userId = getUserId()
        val token = getAuthToken()
        val valid = loggedIn && !userId.isNullOrBlank() && !token.isNullOrBlank()
        return AuthState(
            isLoggedIn = valid,
            userId = if (valid) userId else null,
            authToken = if (valid) token else null
        )
    }

    fun onAuthSuccess(userId: String, authToken: String) {
        prefs.edit()
            .putBoolean(KEY_LOGGED_IN, true)
            .putString(KEY_USER_ID, userId)
            .putString(KEY_AUTH_TOKEN, authToken)
            .apply()
    }

    fun logout() {
        prefs.edit()
            .remove(KEY_LOGGED_IN)
            .remove(KEY_USER_ID)
            .remove(KEY_AUTH_TOKEN)
            .apply()
    }

    fun clearAll() {
        prefs.edit().clear().apply()
    }

    companion object {
        private const val PREFS_NAME = "auth_prefs"
        private const val KEY_LOGGED_IN = "logged_in"
        private const val KEY_USER_ID = "user_id"
        private const val KEY_AUTH_TOKEN = "auth_token"

        @Volatile
        private var INSTANCE: AuthManager? = null

        fun getInstance(context: Context): AuthManager {
            return INSTANCE ?: synchronized(this) {
                INSTANCE ?: AuthManager(
                    context.applicationContext.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
                ).also { INSTANCE = it }
            }
        }

        fun from(prefs: SharedPreferences): AuthManager = AuthManager(prefs)
    }
}